INSERT INTO quest_talk (i_num, str_talk) VALUES
(4160, 'You don`t have enough Noahs. You must pay a fee of 1.5 million Noahs to obtain 500 country CONT.'),
(4161, 'You don`t have enough Noahs. You must pay a fee of 350,000 Noahs to obtain 100 country CONT.'),
(4162, 'There`s nothing I can do for you. I only deal with clans.'),
(4163, 'Your clan has to serve your country more. Only clans above class 3 are eligible to become knight squads.'),
(4164, 'Please relay to your clan leader that this mission can only be completed by him...'),
(4165, 'The knight squad is a combat unit certified by the emperor. As proof of serving your country, only clans above class 3 are eligible to become knight squads. And you must prove your valor and ability. Caitharos is waiting to test you at the coliseum. After defeating Caitharos bring back the [Key of Honor] and 10 million Noahs.'),
(4166, 'The coliseum is home to many trials. The moment you enter the coliseum to undergo the knight squad test, all clan members in the mainland will be transported there. There is no distinction between enemy and friendly forces at the coliseum. Your friend can attack you as well as your opponent. Only the strong will emerge with the [Key of Honor].'),
(4167, 'You may lose valuable EXP in the coliseum. And you may be detained there. Or you may be defeated by other clan members and lose the [Key of Honor].'),
(4168, 'And the most important of all is that you, the clan leader, has to personally acquire the [Key of Honor]. Your friends aid in your combat against Caitharos but they cannot help you to acquire the key. Do not forget. I bid you good luck.'),
(4169, 'Your clan has to serve your country more. Only clans above class 3 are eligible to become knight squads.'),
(4170, 'You don`t have enough Noahs. You need 10 million Noahs for the knight squad registration fee.'),
(4171, 'If you want to join the knight squad you must seize the [Key of Honor] from Caitharos.'),
(4172, 'Did you bring the ingredients below needed for the knight squad promotion?'),
(4173, 'How`s your journey coming along?'),
(4174, 'What kind of mission do you want?'),
(4175, 'Master! Lets go and check out theDark Lunar War.'),
(4176, 'Master! Lets go and check out theDark Lunar War.'),
(4177, 'The news is that the El Moradians are on the move. But its hard to say what theyre up to. I planted a spy in their ranks, but Ive still not had the  Classified Document from them. Look, <selfname>, can you investigate this matter for me?'),
(4178, 'This mission can only be attempted if youre Lvl 45 to Lvl 49.'),
(4179, 'Theres no  Classified Document!  Dark Luna Wars gate stays open until there is a winning nation, between 8am to 10pm every Wednesday. Bring the Classified Document that spy has from there.'),
(4180, 'Have you brought the Classified Document? Whats the situation there? No, everything will be in the document. Give me the  Classified Document please.'),
(4181, 'Master! Lets go and check out theLunar War.'),
(4182, 'Master! Lets go and check out theLunar War.'),
(4183, 'The news is that the El Moradians are on the move. But its hard to say what theyre up to. I planted a spy in their ranks, but Ive still not had the  Classified Document from them. Look, <selfname>, can you investigate this matter for me?'),
(4184, 'This mission can only be attempted if youre Lvl 50 or higher. Come and see me after youve spilt some more blood!'),
