(6366, '<selfname>! Youve already swiped this villages key.'),
(6367, '[Would you like to take the key?]'),
(6368, 'The enemys secrets are in their castle. Ill reward you more for each key you bring me from Asga and Laiva villages and the Doda Camp. Good luck.'),
(6369, 'The enemys secrets are in their castle. Ill reward you more for each key you bring me from Belua and Linnart villages and the Raon Camp. Good luck.'),
