INSERT INTO quest_talk (i_num, str_talk) VALUES
(9021, '[Guard] Melverick has commissioned you to hunt Haunga.'),
(9022, 'Master, [Guard] Melverick has a task that needs to be assigned urgently. At first hearing, it doesnt seem to be a problem that can be completed at once...'),
(9023, '<selfname>! Long time no see. I just want to let you know that we decided to carry out the subjugation of monsters on a large scale this time. However, if we go there as a troop, they all hide so we have planned an operation in which we move ecretly and individually. That is, I have to subdue them alone!'),
(9024, 'First, please catch 30 Kaungas! I tell you this one more time. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 51 to 55, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9025, 'First, please catch 40 Grells! I tell you this one more time. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 51 to 55, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9026, 'First, please catch 40 Apes! I tell you this one more time. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 51 to 55, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9027, 'Master, it has has been completed! Go to Melverick quickly!'),
(9028, 'Oh, you completed the task! Thanks a lot. For your information, please note that this Quest can be perform repeatedly up to 55 levels.'),
(9029, 'Master! [Guard] Zalk has a task that needs to be assigned urgently. At first hearing, it doesnt seem to be a problem that can be completed at once...'),
(9030, '<selfname>! Long time no see. I just want to let you know that we decided to carry out the subjugation of monsters on a large scale this time. However, if we go there as a troop, they all hide so we have planned an operation in which we move in secretly and individually. That is, I have to subdue them alone!'),
(9031, 'First, please catch 30 Kongaus! Ill tell you once more. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 51 to 55, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9032, 'First, please catch 40 Grells! Ill tell you once more. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 51 to 55, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9033, 'First, please catch 40 Apes! Ill tell you once more. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 51 to 55, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9034, 'Master, it has has been completed! Go to Zalk quickly!'),
(9035, 'Oh, you completed the task! Thanks a lot. For your information, please note that this Quest can be perform repeatedly up to 55 levels.'),
(9036, 'Oh! You have come. The guerilla warfare last time was magnificent. I cant forget the sight! So I will assign another task to you. It is a guerilla warfare this time too. Of course, you have to carry out the task by yourself in the same way as you did with the last task.'),
(9037, 'This time, please catch 40 Haungas! Ill tell you once more. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 56 to 59, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
(9038, 'This time, please catch 30 Barons! Ill tell you once more. You have to perform the task by yourself!|# When the party play is performed with the [Repeat Quest] which can perform this Quest up to Lv. 56 to 59, the monster counter doesnt go up but the counter goes up only when solo play is performed.'),
