INSERT INTO quest_talk (i_num, str_talk) VALUES
(10050, 'Welcome to PVP SERVER!!  Its fun to feel the war! You have exercised the power of hope to see! Your ability to show!!'),
(10051, 'Hello? My friend. Do you need help? What I do is in charge of funding for the war. NOAH, Ill support if necessary.'),
(10052, 'Do you need NOAH?'),
(10053, 'I gave to you money. go to battle zone!'),
(10060, 'Its August! Finally its the Fishing season.'),
(10061, 'I£ue heard that a rare fish was caught recently.|It£r a golden . . . I can£s remember . . . |Oh yeah! The Gold Fish! Yes, it£r the Gold Fish! |Please bring the Gold Fish to me if you catch it. I can sell them at a high price at the Market in Moradon.||I£kl give you a special reward if you bring lots of [Gold Fishes] to me. Remember! The more, the better. ||Oh, and please bring [Goby] and [Salmon] to me if you catch them, too. If you bring me 10 [Gobies] and 10 [Salmons], I£kl give you [Gem of Abyss] in exchange. |'),
(10062, 'Oh, it seems like youve caught something. What did you get?'),
(10063, 'I dont think you have enough [Muskipper] nor the [Salmon].'),
(10064, 'one, two, three, ?, nine, ten! Yes you do have 10 each.'),
(10065, 'Here you go. You have [Abyss Jewel]. Hopefully you can obtain good items. Ill give you some [worms].'),
(10067, 'oh! You really caught [Gold Fish]! Show me, show me!'),
(10068, 'Hey..  You dont want to give it to me now? Didnt I say that Ill give you a reward? Think about it. If you give me lots of [Gold Fish] the top 2 people who give me the most fish will get [Master Wings].'),
(10069, 'Even if you dont have many, give me. Youll be rewarded. Ill give you some [worm].'),
(10070, 'Are you kidding me? You dont have one [Gold Fish]. Im gonna take away all your worms so you cant kid anymore.'),
(10080, 'Hello. Hahaha. Im the person whos been to every places on earth and have seen all the monsters around the world. Im the captain of the Wanderer. Would you like to hear my story?'),
(10081, 'For now, there are two things. One, its about [Suspicious spirit] thats wandering around the castle. The second one is about [Unique Pattern] from a Far East Country. Dont they sound interesting?'),
(10082, 'What? You£ue never heard of a story that£r spreading throughout the world? |I£ue heard that [Zigenon], killed by El Morad£r Warrior, became a ghost and is taking vengeance.||You£kl obtain powerful [Core of Ghost], which is very expensive, if you get rid of [Zigenon£r Ghost]. ||Please bring it to me if you get it.| I£kl give you a reward for that. |Let£r help each other. (Giggle)'),
(10083, 'What? You£ue never heard of a story that£r spreading throughout the world? |I£ue heard that [Stone Tailer], killed by El Morad£r Warrior, became a ghost and is taking vengeance.||You£kl obtain powerful [Core of Ghost], which is very expensive, if you get rid of [Stone Tailer£r Ghost]. ||Please bring it to me if you get it.| I£kl give you a reward for that. |Let£r help each other. (Giggle)'),
(10084, 'What? |You£ue never heard of a symbol with the bright energy?||I£ue heard that one Eastern Country is using the symbol on its national flag.|It£r also said that the pieces of the flag are used to make armor for the enemy.|| You can obtain it if you get rid of an enemy in the Frontier Zone. You can make [Taegeuk Symbol] if you combine 6 [Taegeuk Pieces] with a [Flag]. You can purchase a [Flag] from the [Merchant of Islante Nomad].|||This is expensive also, so I£kl give you [Taegeukgi (Korean Flag)] as a reward for that.|'),
(10085, 'You already got the [Nucleus of Spirit] as a reward. Come back tomorrow now.'),
(10086, 'I dont see any [Ying Yang Pattern]. Did you really combine the  [Flags] with 6 [Ying Yang Pieces]? Check it again.'),
(10087, 'It seems like you did make [Ying Yang Pattern]. As I said, heres the flag. Itll give you more exp.Try it once and let me know how it worked.'),
(10088, 'Hey there. I dont think you have [Nucleus of spirit]. Did you even get to meet the spirit? Come back again with it.'),
(10089, 'That!!!  It is really [Nucleus of Spirit]! Oh, wow. Thank you. Ill give you a reward now.'),
(10090, 'How do you like your reward. You dont like it? Hm..  Next time Ill give you another one you would really like.'),
(10091, 'You got 10 [Warriors Article]. Would you like to exchange it with the Slogan?'),
(10100, '[Oh! That is the [Spirit of Alseid]! |I£l so lucky to see that spirit in this kind of place! |Currently, our Mercenary Squad is renting equipment that fits in with your current level for six hours a day. Thank you for showing me [Spirit of Alseid].'),
(10101, 'You don£s have [Spirit of Alseids]. Please check it.'),
(10105, 'Oh, you must be the one who caught lots of [Gold Fish]. Ill give you the [Wing of Expert].'),
(10106, 'They only remember the first. You arent the first. Sorry try it again next time.'),
(10110, 'This is where we dispatch soldiers from El Morad. Cant you see my face?'),
