INSERT INTO quest_talk (i_num, str_talk) VALUES
(10516, 'Ill be using the [Lucky Bag] now. Find me more tomorrow.'),
(10517, 'We need firewood. Please bring 5 branches of [Ice Tree].'),
(10518, '[Ice Tree] is a winter tree that raises only during the winter.'),
(10519, 'Well need at least 5 [Ice Tree]. Please bring me at least 5.'),
(10520, 'You have brought me all 5! Thank you so much. What would you like to have?'),
(10521, 'Its so cold so please bring me more then Ill reward you for it.'),
(10522, 'Hello. Im the fortune teller of [Eslant Wanderer].'),
(10523, 'We were asked to defeat the snowman and deliver 5 [Lucky bag].'),
(10524, 'WE were asked to find [Ice Tree] and bring 5 branches of [Ice Tree].'),
(10525, 'Would you like to try out temporarily how this weapons work? You can rent it for 8 hours and itll cost you 1,000,000.'),
(10526, 'I dont have any support at this time. I thank you for your bravery but youll have to come back later.'),
(10527, 'Why dont you support? Ah, are you asking what kind of support this is? We the [Twilight Guardian] have been battling [Pluwiton Army] for a long time. But they are so strong so were losing our man.'),
(10528, 'If you are interested, please help us. Defeat [Pluwiton] at Under the Castle. Then youll be able to meet [Twilight Guardian] Martin. Deliver the form then hell explain more.'),
(10529, 'I would like to show my appreication for what youve done.'),
(10530, 'Hey, there. It seems you are preparing to battle [Pluwiton Army] But it seems you arent completely ready.'),
(10531, 'Do you know what [Life Crystal] is? If you have this you can ressurect when something happens to you at [Under the Castle].'),
(10532, 'I can give you one per day so take this. And please defeat [Pluwiton].'),
(10533, 'It seems you already received a [Life Crystal]. Please come back tomorrow.'),
(10534, 'I was ordered to deliver [Support form] to [Martin] whos located at [Under the Castle].'),
(10535, 'Test'),
(10536, 'What is this. An application form? Thats right. We thank you for your support and interest.'),
(10537, 'Itll help you. This is what weve collected in the past.'),
(10538, 'You can freely enter [Under the Castle] but the apperance of [Army of Pluwiton] is limited. They are powerful so youll need a good and big party members.'),
(10539, 'I would like to show you my appreciation. Please help us again.'),
(10540, 'Youll apply for [Twilight Guardian]? Do you even have the [Application form]?'),
(10541, 'They already have the form.'),
(10542, 'It seems that the entrance to [Under the Castle] has been locked. Come back later.'),
(10543, 'Testing the Entering'),
(10544, 'You cant enter [Under the Castle]. Move to the other server and apply to enter.'),
(10545, 'There are too many supporters. I cant send you right now even though I know you are brave. But if someone gives up, well send you.'),
(10546, 'Thank you for your interest in supporting the [Twilight Guardian]. But your nation is currently undergoing the battle with [Lunar War]. It seems youll need to participate in [Lunar War] first.'),
(10547, 'You can check the efficiency of these weapons and accessories for 24 hrs. Its free for now.'),
(10548, 'Master! [Merchants Daughter] Manisia is looking for someone wholl help her.'),
(10549, 'Master! [Merchants Daughter] Manisia is looking for someone wholl help her.'),
(10550, 'You are a single?? No?? [Valentines Day] is a specialy day. The day you can propose to the loved ones with [Chocolate]. Bring me 10 more choclate first.'),
(10551, 'You would like to be loved? Then bring [10 Chocolate]. You can obtain [Chocolate] by attacking [Cone Hat] with [Bamboo trees].'),
(10552, 'You have collected all 10 [Chocolate]. If you take this youll propose will be a success! But Ill take all chocolate from you now.'),
(10553, 'You are a lovely one. Please come back tomorrow.'),
(10554, 'You dont have any space in the inventory~~'),
(10555, 'You are a single?? No?? [Valentines Day] doesnt apply to us. Please bring me [20 Chocolate]. You need to be stronger. You need to hunt [Cone hat].'),
(10556, 'You want to be strong? Then bring me [20 Chocolate]. You can get chocolate by attacking [Cone Hat] with the [Bamboo].'),
(10557, 'You have collected all [20 Choclate]. You are a brave one.'),
(10558, 'You are already a brave one.'),
(10559, 'Hello. Its the new years already. Be happy~'),
(10560, 'Attention! For the glory of Karus! You are at a level to attend a battle.'),
(10561, 'If you are a Karus Citizen, you must know what Elmorad has done to us. Now its time to take revenge.'),
(10562, '[Ardream] is where level 50 - 59 players can battle. Its important to have a good strategy and skills.'),
(10563, 'Yes, Battle skill will be learned from attending battles.'),
(10564, 'You do not have [Ardream Dispatching Form] or your level isnt fit for entering [Ardream]. Youll need to enter [Ronarkland Base] or [Ronarkland].'),
(10565, 'If you are a citizen of Karus, you know that you have to show bravery. You now have a chance to show off.'),
(10566, '[Ronarkland Base] is where level 60 - 69 can enter. You can really show off your skills that you have built for a long time. But youll still need to be careful.'),
(10567, 'Yes please show off your skills!'),
(10568, 'You do not have [Ronarkland Base Dispatching Form] or your level isnt fit for entering [Ronarkland Base]. Youll need to enter [Ronarkland].'),
(10569, 'Attention! For the glory of Elmorad! You are at a level to attend a battle.'),
