INSERT INTO quest_talk (i_num, str_talk) VALUES
(11557, 'So shiny. Ill give you the reward later.'),
(11558, 'Help me!!!  I cant sleep because of those harpies.'),
(11559, 'Please forgive me if I was rude the last time. Please get rid of those awful harpies. And bring me 20 harpies wings. Then Ill give you reward.'),
(11560, 'Thank you so much!'),
(11561, 'Im the only one left at this spacious Ronarkland. | !! You can see me? Thats great.'),
(11562, 'You must be the God of Contribution. You want to be the God of War? Then deliver this Warmongers evidence and 3 Warmongers Coins to spy whos near the enemy gate within 6 hours.'),
(11563, 'You dont know what the ghost can do! You wanted to trick the ghost!?'),
(11564, 'I dont think we can finish up today. Lets do it tomorrow.'),
(11565, 'Because of you, hes able to enter nirvana. This is to show my appreciation.'),
(11566, 'I heard my friends soul is wandering around Eslant. | If you invade Eslant youll meet the soul.'),
(11567, '??? ????? ?? ?? ????? ??? ???. ??? ?? ???????? ???? ??? ???? ??? ??? ???.. ?? ????? ??.. ??? ?? ??? ???. ???? ??? ???? ????? ? ??? ???'),
(11568, 'I dont think Ive done much for our country. | I think you might be the hero though. Could you prove your skills to me? | Please bring 3 warmongers Coin. And go visit Eslant Fortune teller.'),
(11569, 'Do you know the item called Start of the Change? If you obtain it, bring it to me. Its related to the reason for the geographical different in Ronarkland. Bring it to me to get reward.'),
(11570, 'You havent started Start of the Change'),
(11571, 'Bring 10 start of the change, then after drawing youll get a chance to receive prize.'),
(11572, 'Because of the Earthquake, the geography has been changed in Ronarkland. How do you like the new Ronarkland?'),
(11573, 'You dont have enough space in your bag.'),
(11574, 'Didnt the dead war soul told you something?'),
(11575, 'If you get recognized as the God of Transportation by the war soul, youll be able to receive the test.'),
(11576, 'If you get recognized as the God of Contribution by the war soul, youll be able to receive the test.'),
(11577, 'This is!  God job. You brought the war coin. Youll contribute all of those? If you contribute all, youll become the god of contribution.'),
(11578, 'If you bring warmongers coins youll be accepted as the contribution god.'),
(11579, 'You havent passed the test for transportation.'),
(11580, 'You havent passed the test for contribution.'),
(11581, 'If you are done with what I told you to do, go talk to Eslant Fortune teller.'),
(11582, 'You are not the god of transportation.'),
(11583, 'You are not the god of contribution.'),
(11584, 'Youve done well today. Come back tomorrow.'),
(11585, 'If you want to take revenge for the war soul youll need to defeat 3 enemy.'),
(11586, 'Bring me at least 3.'),
(11587, 'Youll need to pass the test in order to become the war God. | In order to meet the resented war soul youll need to invade enemys guard tower.'),
(11588, 'Spy is located where the enemys camp entrance is.'),
(11589, 'In order to test your skills, Ill take all the warmongers coins.'),
(11590, 'Its childrens day soon. But I have no money to buy something for my children.'),
(11591, 'Really? Thank you? Ill really repay you back for this. | But I have one more favor to ask you.'),
(11592, 'I have to wrap the gift but the wrapper is near the Chaos area. Could you bring me one?'),
(11593, 'If you participate in Chaos youll get one wrapper.'),
(11594, 'Thank you so much! Thank you..   My children will love these gifts too. || This isnt much but I want to give you this traditional box. I dont need it so Ill give it to you.'),
(11595, 'Thank you.'),
(11596, 'sobbing..(small girl crying sadly at the corner.)'),
(11597, 'Sobbing..  For parents day I collected carnations but monsters have stolen them all. T.T'),
(11598, 'If you are hunting and you see carnations, could you bring 10 of them? | There is more than one monster. T.T'),
(11599, 'You dont have enough carnations.'),
(11600, 'Wow! Thank you!!!! Ill give you one.'),
(11601, 'Welcome. The reason I called you is to tell you that theres celebration for the Gods coming. Could you bring some lanterns?'),
(11602, 'If you dismantle items that are normal to above with [Unknown Narki] youll be able to get the lanterns. Bring me 5.'),
(11603, 'You dont have all 5.'),
(11604, 'Good. Ill now give you a small gift from Kaishan.'),
(11605, 'Well need to hang the lanter once a day.'),
(11606, 'Hey could you do me a favor?'),
(11607, 'I want to make hammer for my teacher for teachers day. But I cant make it because I lack in ingrediants.'),
(11608, 'Theres a guy named [Unknown Narki] at Moradon. Hes the one who can make the [master craftmans touch]. Bring me 5 master craftmans touch.'),
(11609, 'You dont have all 5.'),
(11610, 'Thank you. (a bit later)  Im done with the hammer! Bring this to my teacher heppa.'),
(11611, 'My disciple, Shojin is giving me this? Oh.. Thank you. This must be heavy for you to deliver. Take this.'),
(11612, 'I got mixed up with the other date..  Haha. Could you come back tomorrow?'),
(11613, 'Rent, Living expense, my daughters studying expense, interest, supply expense. Ah!!!! What am I gonna do?'),
(11614, 'Tell Shojin that Ill make a good use of the hammer. Come back tomorrow.'),
(11615, 'Its teachers day and my only disciple only knows of work.'),
(11616, 'Can you go see if Shojin is preparing something for me?'),
(11617, 'OH!!! This is an awesome hammer! I like it a lot~ Tell Shojin thank you.  Take one for yourself.'),
(11618, 'Was Shojin preparing for something?'),
(11619, 'Are you kidding me? You have no money. You think Im a beggar? Theres the owner at the towns entrance who has an envelop full of money. Give that to me.'),
(11620, '10 year Anniversary Celebration Description.'),
(11621, '10 year Anniversary Celebration Description.'),
(11622, 'Its free experience of Knight Online period.'),
(11623, 'Knight Genie Testing Period Description.'),
(11624, 'Hello, May are you help you?'),
(11625, 'You need a [Gryphons Armor Voucher] to get the Gryphon Armor. A [Gryphons Armor Voucher] can be purchased from the Power-up store.'),
(11626, 'You have selected Gryphon Armor HP+200 Nice isnt it? Do you really want it?'),
(11627, 'You have selected Gryphon Armor Defense +30. Nice isnt it? Do you really want it?'),
(11628, 'You have selected Gryphon Armor EXP Gain Rate +4%. Nice isnt it? Do you really want it?'),
(11629, 'You have selected Gryphon Armor Noah Drop Rate +6%. Nice isnt it? Do you really want it?'),
(11630, 'You have selected Gryphon Armor HP+100 Nice isnt it? Do you really want it?'),
(11631, 'You have selected Gryphon Armor Defense +20. Nice isnt it? Do you really want it?'),
(11632, 'You have selected Gryphon Armor EXP Gain Rate +2%. Nice isnt it? Do you really want it?'),
(11633, 'You have selected Gryphon Armor Noah Drop Rate +3%. Nice isnt it? Do you really want it?'),
(11634, 'You need a [Gryphons Helmet Voucher] to get the Gryphon Helmet. A [Gryphons Helmet Voucher] can be purchased from the Power-up store.'),
(11635, 'There are many options available to you with Minerva Clothing. Select your desired option.'),
(11636, 'It requires a [Minerva Armor Certificate]. Please check again.'),
(11637, 'It requires a [Minerva Helmet Certificate]. Please check again.'),
(11638, '10 year Anniversary Celebration Description.'),
(11639, '10 year Anniversary Celebration Description.'),
(11640, 'If you bring a fee of  3000 Noah, the [Tycoon] Kaishan will give you the first transfer. [Tycoon] Kaishan is up in the north from the center of Moradon.'),
(11641, 'If you bring a fee of  3000 Noah, the [Tycoon] Kaishan will give you the first transfer. [Tycoon] Kaishan is up in the north from the center of Moradon.'),
(11642, 'If you bring a fee of  3000 Noah, the [Tycoon] Kaishan will give you the first transfer. [Tycoon] Kaishan is up in the north from the center of Moradon.'),
(11643, 'If you bring a fee of  3000 Noah, the [Tycoon] Kaishan will give you the first transfer. [Tycoon] Kaishan is up in the north from the center of Moradon.'),
(11644, 'If you bring a fee of  3000 Noah, the [Tycoon] Kaishan will give you the first transfer. [Tycoon] Kaishan is up in the north from the center of Moradon.'),
(11645, 'Welcome. Please defeat the monster Cake with a fork and bring me 5 slices of cake.'),
(11646, 'Use the fork to defeat the enemy.'),
(11647, 'Yay! Youve got it. Wait here. Ill lift off the spell. Yap! | Youll be able to eat now. Take the cake you want.'),
(11648, 'Im so hungry. Cooks are making the cake with special ingredients but I have no time to go eat.'),
(11649, 'Cake!...cake!...cake!...'),
(11650, 'This!! Its cake! Thank you! I didnt ask you for it but Ill give this to you now.'),
(11651, 'Welcome. These days there are libertines who are attacking towns women. Bring the bamboo from the merchant and punish them. Bring the documents libertines have.'),
(11652, 'You arent done punishing them.'),
(11653, 'This must be!!!   How can the libertines have the appreciation letter! Who are they?'),
(11654, 'You had a tough day. Thank you. Come back tomorrow.'),
(11655, 'You can exchange once a day.'),
